#include <bits/stdc++.h>
using namespace std;

const int N=1e3+10;

int n;
double f[N][N];

int main(){
    scanf("%d",&n);
    n/=2;
    f[0][2]=f[2][0]=1;
    for(int i=0;i<=n;i++)
        for(int j=0;j<=n;j++){
            if(i+j<=2)
                continue;
            if(!i)
                f[i][j]=f[i][j-1];
            else if(!j)
                f[i][j]=f[i-1][j];
            else
                f[i][j]=1.0/2.0*(f[i-1][j]+f[i][j-1]);
        }
    printf("%.4lf",f[n][n]);
    return 0;
}
